// --- Authenticated Fetch Wrapper ---
let isRefreshing = false;
let refreshSubscribers = [];

function onTokenRefreshed(newToken) {
  refreshSubscribers.forEach((callback) => callback(newToken));
  refreshSubscribers = [];
}

function addRefreshSubscriber(callback) {
  refreshSubscribers.push(callback);
}

async function authenticatedFetch(url, options = {}) {
  let accessToken = TokenStorage.getAccessToken();

  if (TokenStorage.isTokenExpired() && TokenStorage.getRefreshToken()) {
    if (!isRefreshing) {
      isRefreshing = true;
      try {
        const tokenData = await OAuthService.refreshAccessToken();
        isRefreshing = false;
        onTokenRefreshed(tokenData.access_token);
        accessToken = tokenData.access_token;
      } catch (error) {
        isRefreshing = false;
        refreshSubscribers = [];
        TokenStorage.clearTokens();
        window.location.href = '/';
        throw error;
      }
    } else {
      accessToken = await new Promise((resolve) => {
        addRefreshSubscriber((token) => resolve(token));
      });
    }
  }

  if (!accessToken) {
    throw new Error('No access token available');
  }

  const fetchOptions = {
    ...options,
    headers: {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
    },
  };

  const response = await fetch(url, fetchOptions);

  // If 401, try to refresh once
  if (response.status === 401 && TokenStorage.getRefreshToken()) {
    try {
      const tokenData = await OAuthService.refreshAccessToken();
      const retryOptions = {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${tokenData.access_token}`,
        },
      };
      return fetch(url, retryOptions);
    } catch {
      TokenStorage.clearTokens();
      window.location.href = '/';
      throw new Error('Session expired');
    }
  }

  return response;
}

