// --- OAuth Callback Page ---
function CallbackPage() {
  const { handleCallback, isAuthenticated, error } = useAuth();
  const { searchParams, navigate } = useRouter();
  const [processing, setProcessing] = useState(true);

  useEffect(() => {
    const code = searchParams.get('code');
    const state = searchParams.get('state');
    const errorParam = searchParams.get('error');
    const errorDescription = searchParams.get('error_description');

    if (errorParam) {
      setProcessing(false);
      return;
    }

    if (code && state) {
      handleCallback(code, state).then(() => {
        setProcessing(false);
      });
    } else {
      setProcessing(false);
    }
  }, [searchParams, handleCallback]);

  useEffect(() => {
    if (isAuthenticated) {
      // Clean the URL and navigate to dashboard
      window.history.replaceState({}, '', '/');
      navigate('/dashboard');
    }
  }, [isAuthenticated, navigate]);

  const errorParam = searchParams.get('error');
  const errorDescription = searchParams.get('error_description');

  if (errorParam) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement('div', { style: styles.errorBox }, '⚠️ ', errorDescription || errorParam),
        React.createElement(
          'button',
          {
            style: { ...styles.button, ...styles.secondaryButton },
            onClick: () => navigate('/'),
          },
          'Back to Login'
        )
      )
    );
  }

  if (error) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement('div', { style: styles.errorBox }, '⚠️ ', error),
        React.createElement(
          'button',
          {
            style: { ...styles.button, ...styles.secondaryButton },
            onClick: () => navigate('/'),
          },
          'Back to Login'
        )
      )
    );
  }

  if (processing) {
    return React.createElement(LoadingSpinner, { message: 'Completing sign in...' });
  }

  return React.createElement(LoadingSpinner, { message: 'Redirecting...' });
}

