function ApiTestPage() {
  const { authenticatedFetch: authFetch } = useAuth();
  const [apiUrl, setApiUrl] = useState(OAUTH_CONFIG.apiBaseUrl + '/me');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState(null);

  const callApi = async () => {
    setLoading(true);
    setApiError(null);
    setResult(null);
    try {
      const response = await authFetch(apiUrl);
      const data = await response.json();
      setResult(JSON.stringify(data, null, 2));
    } catch (err) {
      setApiError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return React.createElement(
    'div',
    null,
    React.createElement(
      'div',
      { style: styles.header },
      React.createElement('h1', { style: styles.headerTitle }, '🧪 API Tester')
    ),
    React.createElement(
      'div',
      { style: { ...styles.container, paddingBottom: '100px' } },
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement('h3', { style: { margin: '0 0 12px', fontSize: '16px' } }, 'Test Authenticated API Call'),
        React.createElement('input', {
          type: 'text',
          value: apiUrl,
          onChange: (e) => setApiUrl(e.target.value),
          placeholder: 'API endpoint URL',
          style: {
            width: '100%',
            padding: '12px',
            borderRadius: '8px',
            border: '1px solid #ddd',
            fontSize: '14px',
            marginBottom: '12px',
            boxSizing: 'border-box',
          },
        }),
        React.createElement(
          'button',
          {
            style: { ...styles.button, ...styles.primaryButton },
            onClick: callApi,
            disabled: loading,
          },
          loading ? '⏳ Calling...' : '📡 Send Request'
        )
      ),
      apiError &&
        React.createElement('div', { style: { ...styles.card, ...styles.errorBox } }, '⚠️ ', apiError),
      result &&
        React.createElement(
          'div',
          { style: styles.card },
          React.createElement('h3', { style: { margin: '0 0 12px', fontSize: '16px' } }, '📋 Response'),
          React.createElement('pre', { style: styles.apiResult }, result)
        )
    )
  );
}

