// --- Bottom Navigation ---
function BottomNav({ currentPath, navigate }) {
  const items = [
    { path: '/dashboard', icon: '🏠', label: 'Home' },
    { path: '/api-test', icon: '🧪', label: 'API Test' },
    { path: '/settings', icon: '⚙️', label: 'Settings' },
  ];

  return React.createElement(
    'nav',
    { style: styles.navBar },
    items.map((item) =>
      React.createElement(
        'button',
        {
          key: item.path,
          style: {
            ...styles.navItem,
            ...(currentPath === item.path ? styles.navItemActive : {}),
          },
          onClick: () => navigate(item.path),
        },
        React.createElement('span', { style: styles.navIcon }, item.icon),
        item.label
      )
    )
  );
}

// --- Protected Route Wrapper ---
function ProtectedRoute({ children }) {
  const { isAuthenticated, isLoading } = useAuth();
  const { navigate } = useRouter();

  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      navigate('/');
    }
  }, [isAuthenticated, isLoading, navigate]);

  if (isLoading) {
    return React.createElement(LoadingSpinner, { message: 'Authenticating...' });
  }

  if (!isAuthenticated) {
    return null;
  }

  return children;
}

// --- Main App Component ---
function App() {
  const { path, navigate } = useRouter();
  const { isAuthenticated, isLoading } = useAuth();

  // Determine which page to render
  let content;

  if (path === '/callback') {
    content = React.createElement(CallbackPage, null);
  } else if (!isAuthenticated && !isLoading) {
    content = React.createElement(LoginPage, null);
  } else if (isLoading) {
    content = React.createElement(LoadingSpinner, { message: 'Loading...' });
  } else {
    let page;
    switch (path) {
      case '/api-test':
        page = React.createElement(ApiTestPage, null);
        break;
      case '/settings':
        page = React.createElement(SettingsPage, null);
        break;
      case '/dashboard':
      default:
        page = React.createElement(DashboardPage, null);
        break;
    }

    content = React.createElement(
      ProtectedRoute,
      null,
      React.createElement(
        React.Fragment,
        null,
        page,
        React.createElement(BottomNav, { currentPath: path, navigate })
      )
    );
  }

  return React.createElement('div', { style: styles.app }, content);
}

// --- App Root ---
function AppRoot() {
  return React.createElement(AuthProvider, null, React.createElement(App, null));
}

// --- Mount ---
const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(React.createElement(React.StrictMode, null, React.createElement(AppRoot, null)));
}

